import * as _backstage_frontend_test_utils from '@backstage/frontend-test-utils';
import { MockWithApiFactory } from '@backstage/frontend-test-utils';
import { ApiFactory, ExtensionDefinition } from '@backstage/frontend-plugin-api';
import { Entity } from '@backstage/catalog-model';
import { CatalogApi } from '@backstage/catalog-client';
import * as react_jsx_runtime from 'react/jsx-runtime';
import { PropsWithChildren } from 'react';
import { DefaultEntityFilters, EntityListContextProps } from '@backstage/plugin-catalog-react';

/**
 * Creates a fake catalog client that handles entities in memory storage. Note
 * that this client may be severely limited in functionality, and advanced
 * functions may not be available at all.
 *
 * @public
 */
declare function catalogApiMock(options?: {
    entities?: Entity[];
}): MockWithApiFactory<CatalogApi>;
/**
 * A collection of mock functionality for the catalog service.
 *
 * @public
 */
declare namespace catalogApiMock {
    /**
     * Creates a fake catalog client that handles entities in memory storage. Note
     * that this client may be severely limited in functionality, and advanced
     * functions may not be available at all.
     */
    const factory: (options?: {
        entities?: Entity[];
    }) => ApiFactory<CatalogApi, CatalogApi, {}>;
    /**
     * Creates a catalog client whose methods are mock functions, possibly with
     * some of them overloaded by the caller.
     */
    const mock: (partialImpl?: Partial<CatalogApi> | undefined) => _backstage_frontend_test_utils.ApiMock<CatalogApi>;
}

/**
 * Simplifies testing of code that uses the entity list hooks.
 *
 * @public
 */
declare function MockEntityListContextProvider<T extends DefaultEntityFilters = DefaultEntityFilters>(props: PropsWithChildren<{
    value?: Partial<EntityListContextProps<T>>;
}>): react_jsx_runtime.JSX.Element;

/**
 * Options for creating a test entity page.
 * @public
 */
interface TestEntityPageOptions {
    /**
     * The entity to provide in the EntityProvider context.
     */
    entity: Entity;
}
/**
 * Creates a test entity page extension that provides EntityProvider context
 * and accepts entity extensions (cards, content) as inputs.
 *
 * This utility simplifies testing entity extensions by eliminating the need
 * for manual EntityProvider wrapping and route configuration.
 *
 * @remarks
 *
 * The test page uses input redirects to accept both:
 * - Entity cards (normally attach to `entity-content:catalog/overview`)
 * - Entity content (normally attach to `page:catalog/entity`)
 *
 * Cards are rendered in a simple container. Content extensions follow
 * standard routing behavior, with a single content optimization that
 * renders directly without routing.
 *
 * @example
 * ```tsx
 * import { createTestEntityPage } from '@backstage/plugin-catalog-react/testUtils';
 * import { renderTestApp } from '@backstage/frontend-test-utils';
 *
 * const mockEntity = {
 *   apiVersion: 'backstage.io/v1alpha1',
 *   kind: 'Component',
 *   metadata: { name: 'test' },
 *   spec: { type: 'service' },
 * };
 *
 * // Testing an entity card
 * renderTestApp({
 *   extensions: [createTestEntityPage({ entity: mockEntity }), myEntityCard],
 * });
 *
 * // Testing entity content
 * renderTestApp({
 *   extensions: [createTestEntityPage({ entity: mockEntity }), myEntityContent],
 * });
 * ```
 *
 * @public
 */
declare function createTestEntityPage(options: TestEntityPageOptions): ExtensionDefinition;

export { MockEntityListContextProvider, catalogApiMock, createTestEntityPage };
export type { TestEntityPageOptions };
